from typing import List, Optional, Tuple


class TreeNode:
    def __init__(self, word: str):
        self.word = word
        self.left: Optional["TreeNode"] = None
        self.right: Optional["TreeNode"] = None


class Solution:
    def optimalBST(self, words: List[str], frequency: List[int]) -> Tuple[int, Optional[TreeNode]]:
        n = len(words)
        if n == 0:
            return 0, None

        # prefix[k] = sum of frequency[0..k-1]; rangeSum(i,j) = prefix[j+1]-prefix[i]
        prefix = [0] * (n + 1)
        for k in range(n):
            prefix[k + 1] = prefix[k] + frequency[k]

        def range_sum(i: int, j: int) -> int:
            return prefix[j + 1] - prefix[i]

        # dp[i][j] = min cost for words i..j ; root[i][j] = chosen root index
        dp = [[0] * n for _ in range(n)]
        root = [[0] * n for _ in range(n)]

        for i in range(n):
            dp[i][i] = frequency[i]
            root[i][i] = i

        for length in range(2, n + 1):
            for i in range(0, n - length + 1):
                j = i + length - 1
                best = float("inf")
                s = range_sum(i, j)
                for r in range(i, j + 1):
                    left = dp[i][r - 1] if r > i else 0
                    right = dp[r + 1][j] if r < j else 0
                    cost = left + right + s
                    if cost < best:
                        best = cost
                        root[i][j] = r
                dp[i][j] = best

        def build(i: int, j: int) -> Optional[TreeNode]:
            if i > j:
                return None
            r = root[i][j]
            node = TreeNode(words[r])
            node.left = build(i, r - 1)
            node.right = build(r + 1, j)
            return node

        return dp[0][n - 1], build(0, n - 1)


def brute(words, frequency):
    n = len(words)
    if n == 0:
        return 0
    from functools import lru_cache

    @lru_cache(None)
    def solve(i, j):
        if i > j:
            return 0
        s = sum(frequency[i:j + 1])
        return min(solve(i, r - 1) + solve(r + 1, j) + s for r in range(i, j + 1))
    return solve(0, n - 1)


if __name__ == "__main__":
    import random

    # given example
    words = ["apple", "banana", "cherry"]
    freq = [30, 10, 40]
    cost, tree = Solution().optimalBST(words, freq)
    print("example cost:", cost)  # expect 130

    # edge: single
    print("single:", Solution().optimalBST(["a"], [5])[0])  # 5

    # edge: two
    print("two:", Solution().optimalBST(["a", "b"], [1, 100])[0])

    # random oracle check vs brute force
    ok = True
    for _ in range(2000):
        n = random.randint(1, 8)
        f = [random.randint(1, 20) for _ in range(n)]
        w = [chr(ord('a') + k) * (k + 1) for k in range(n)]
        c1 = Solution().optimalBST(w, f)[0]
        c2 = brute(w, f)
        if c1 != c2:
            ok = False
            print("MISMATCH", f, c1, c2)
            break
    print("random oracle match:" , ok)
